async refresh(
    userId: string,
    deviceOwnershipId: string,
    { name, notificationToken, platform }: DeviceRefreshRequestDto,
    requestLog: IRequestLog
): Promise<IResponseReturn<void>> {
    const existDeviceOwnership =
        await this.deviceOwnershipRepository.existActive(
            userId,
            deviceOwnershipId
        );
    if (!existDeviceOwnership) {
        throw new NotFoundException({
            statusCode: EnumDeviceStatusCodeError.notFound,
            message: 'device.error.notFound',
        });
    }

    try {
        await this.deviceOwnershipRepository.refresh(
            userId,
            existDeviceOwnership.id,
            {
                name,
                notificationToken,
                platform,
            },
            requestLog
        );

        return;
    } catch (err: unknown) {
        throw new InternalServerErrorException({
            statusCode: EnumAppStatusCodeError.unknown,
            message: 'http.serverError.internalServerError',
            _error: err,
        });
    }
}

async remove(
    userId: string,
    deviceOwnershipId: string,
    requestLog: IRequestLog
): Promise<IResponseReturn<void>> {
    const existDeviceOwnership =
        await this.deviceOwnershipRepository.existActive(
            userId,
            deviceOwnershipId
        );
    if (!existDeviceOwnership) {
        throw new NotFoundException({
            statusCode: EnumDeviceStatusCodeError.notFound,
            message: 'device.error.notFound',
        });
    }

    try {
        const sessions =
            await this.sessionRepository.findActiveByDeviceOwnership(
                userId,
                existDeviceOwnership.id
            );

        await Promise.all([
            this.deviceOwnershipRepository.remove(
                userId,
                existDeviceOwnership.id,
                requestLog,
                userId
            ),
            this.sessionUtil.deleteAllLogins(userId, sessions),
        ]);

        return;
    } catch (err: unknown) {
        throw new InternalServerErrorException({
            statusCode: EnumAppStatusCodeError.unknown,
            message: 'http.serverError.internalServerError',
            _error: err,
        });
    }
}

async updateMetadataByAdmin(
    id: string,
    data: FeatureFlagUpdateMetadataRequestDto
): Promise<IResponseReturn<FeatureFlagResponseDto>> {
    const featureFlag = await this.featureFlagRepository.findOneById(id);
    if (!featureFlag) {
        throw new NotFoundException({
            statusCode: EnumFeatureFlagStatusCodeError.notFound,
            message: 'featureFlag.error.notFound',
        });
    }

    const validated = this.featureFlagUtil.checkMetadataKey(
        featureFlag.metadata as IFeatureFlagMetadata,
        data.metadata
    );
    if (!validated) {
        throw new BadRequestException({
            statusCode: EnumFeatureFlagStatusCodeError.invalidMetadata,
            message: 'featureFlag.error.invalidMetadata',
        });
    }

    const [updated] = await Promise.all([
        this.featureFlagRepository.updateMetadata(id, data),
        this.featureFlagUtil.deleteCacheByKey(featureFlag.key),
    ]);

    const mapped: FeatureFlagResponseDto =
        this.featureFlagUtil.mapOne(updated);

    return {
        data: mapped,
    };
}

async processWelcomeByAdmin({
    data: { proceedBy, userId, data },
}: Job<
    INotificationWorkerPayload<INotificationWelcomeByAdminPayload>,
    unknown,
    EnumNotificationProcess
>): Promise<IQueueResponse> {
    const user = await this.userRepository.findOneActiveById(userId);

    if (!user) {
        return {
            message:
                'User not found, skipping welcome by admin notification',
        };
    }

    const notificationId = this.databaseUtil.createId();
    const emailPayload: INotificationEmailSendPayload = {
        userId: user.id,
        email: user.email,
        username: user.username,
        notificationId,
    };

    const results = await Promise.allSettled([
        this.notificationRepository.createWelcomeByAdmin(
            notificationId,
            user.id,
            user.username,
            proceedBy
        ),
        this.notificationEmailUtil.sendWelcomeByAdmin(emailPayload, data),
    ]);

    return { message: 'Welcome by admin notification processed', results };
}

