async verifyEmail(
    { token }: UserVerifyEmailRequestDto,
    requestLog: IRequestLog
): Promise<IResponseReturn<void>> {
    const hashedToken = this.userUtil.hashedToken(token);
    const verification =
        await this.userRepository.findOneActiveByVerificationEmailToken(
            hashedToken
        );
    if (!verification) {
        throw new BadRequestException({
            statusCode: EnumUserStatusCodeError.tokenInvalid,
            message: 'user.error.verificationTokenInvalid',
        });
    }

    try {
        await this.userRepository.verifyEmail(
            verification.id,
            verification.userId,
            requestLog
        );

        // @note: send email after all creation
        await this.notificationUtil.sendVerifiedEmail(verification.userId, {
            reference: verification.reference,
        });

        return;
    } catch (err: unknown) {
        throw new InternalServerErrorException({
            statusCode: EnumAppStatusCodeError.unknown,
            message: 'http.serverError.internalServerError',
            _error: err,
        });
    }
}

private async handleTwoFactorValidation(
    user: IUser,
    { method, code, backupCode }: IAuthTwoFactorVerify
): Promise<IAuthTwoFactorVerifyResult> {
    const retryAfterMs =
        await this.authTwoFactorUtil.getLockTwoFactorAttempt(user);
    if (retryAfterMs > 0) {
        throw new RequestTooManyException({
            statusCode:
                EnumAuthStatusCodeError.twoFactorAttemptTemporaryLock,
            message: 'auth.error.twoFactorAttemptTemporaryLock',
            messageProperties: {
                retryAfterSeconds: retryAfterMs / 1000,
            },
        });
    }

    const verified = await this.authTwoFactorUtil.verifyTwoFactor(
        user.twoFactor,
        {
            method,
            code,
            backupCode,
        }
    );
    if (!verified.isValid) {
        await this.userRepository.increaseTwoFactorAttempt(user.id);

        if (this.authTwoFactorUtil.checkAttempt(user)) {
            await this.authTwoFactorUtil.lockTwoFactorAttempt(user);
        }

        throw new UnauthorizedException({
            statusCode: EnumAuthStatusCodeError.twoFactorInvalid,
            message: 'auth.error.twoFactorInvalid',
        });
    }

    await this.userRepository.resetTwoFactorAttempt(user.id);

    return verified;
}

createPassword(
    userId: string,
    password: string,
    options?: IAuthPasswordOptions
): IAuthPassword {
    const today = this.helperService.dateCreate();
    const salt: string = this.helperService.bcryptGenerateSalt(
        this.passwordSaltLength
    );
    const passwordExpired: Date = this.helperService.dateForward(
        today,
        this.helperService.dateCreateDuration({
            seconds: options?.temporary
                ? this.passwordExpiredTemporaryInSeconds
                : this.passwordExpiredInSeconds,
        })
    );
    const passwordHash = this.helperService.bcryptHash(password, salt);
    const passwordPeriodExpired: Date = this.helperService.dateForward(
        today,
        this.helperService.dateCreateDuration({
            seconds: this.passwordPeriodInSeconds,
        })
    );
    const passwordEncrypted: string = this.encryptPassword(
        userId,
        password
    );

    return {
        passwordHash,
        passwordExpired,
        passwordCreated: today,
        passwordPeriodExpired,
        passwordEncrypted,
    };
}

async transform(
    value: {
        cursor?: string;
        perPage?: number | string;
    } & IPaginationQueryCursorParams
): Promise<IPaginationQueryCursorParams> {
    try {
        const finalPerPage = this.validatePerPage(value.perPage);
        const trimmedCursor = this.validateAndSanitizeCursor(
            value.cursor
        );

        this.addToRequestInstance(finalPerPage, trimmedCursor);

        return {
            ...value,
            limit: finalPerPage,
            cursor: trimmedCursor,
            cursorField: defaultCursorField,
        };
    } catch (error) {
        if (error instanceof UnprocessableEntityException) {
            throw error;
        }

        throw new UnprocessableEntityException({
            statusCode: EnumPaginationStatusCodeError.invalidCursorPaginationParams,
            message: 'pagination.error.invalidCursorPaginationParams',
        });
    }
}

transform(
    value: {
        page?: number | string;
        perPage?: number | string;
    } & IPaginationQueryOffsetParams
): IPaginationQueryOffsetParams {
    try {
        const finalPage = this.validateAndParsePage(value.page);
        const finalPerPage = this.validateAndParsePerPage(
            value.perPage
        );

        const skip = (finalPage - 1) * finalPerPage;
        this.addToRequestInstance(finalPage, finalPerPage);

        return {
            ...value,
            limit: finalPerPage,
            skip: skip,
        };
    } catch (error) {
        if (error instanceof UnprocessableEntityException) {
            throw error;
        }

        throw new UnprocessableEntityException({
            statusCode:
                EnumPaginationStatusCodeError.invalidOffsetPaginationParams,
            message: 'pagination.error.invalidOffsetPaginationParams',
        });
    }
}

static forRootAsync(options: TypegooseModuleAsyncOptions): DynamicModule {
  const connectionName = getConnectionToken(options.connectionName);

  const connectionNameProvider = {
    provide: TYPEGOOSE_CONNECTION_NAME,
    useValue: connectionName
  };

  const connectionProvider = {
    provide: connectionName,
    useFactory: (typegooseModuleOptions: TypegooseModuleOptions) => {
      const {
        uri,
        ...typegooseOptions
      } = typegooseModuleOptions;
      return mongoose.createConnection(uri, typegooseOptions);
    },
    inject: [TYPEGOOSE_MODULE_OPTIONS] // inject output of async config creator
  };
  const asyncProviders = this.createAsyncProviders(options);
  return {
    module: TypegooseCoreModule,
    imports: options.imports, // imports from async for root
    providers: [
      ...asyncProviders,
      connectionProvider,
      connectionNameProvider
    ],
    exports: [connectionProvider]
  };
}

private static createAsyncFlowProducerProviders(
  options: RegisterFlowProducerAsyncOptions,
): Provider[] {
  const optionalSharedConfigHolder = createConditionalDepHolder(
    getSharedConfigToken(options.configKey),
    BULL_CONFIG_DEFAULT_TOKEN,
  );

  if (options.useExisting || options.useFactory) {
    return [
      optionalSharedConfigHolder,
      this.createAsyncFlowProducerOptionsProvider(
        options,
        optionalSharedConfigHolder,
      ),
    ];
  }
  if (!options.useClass) {
    // fallback to the "registerFlowProducer" in case someone accidentally used the "registerFlowProducerAsync" instead
    return createFlowProducerOptionProviders([options]);
  }
  const useClass = options.useClass;
  return [
    optionalSharedConfigHolder,
    this.createAsyncFlowProducerOptionsProvider(
      options,
      optionalSharedConfigHolder,
    ),
    {
      provide: useClass,
      useClass,
    },
  ];
}

(processor: BullQueueProcessor) => {
